'use client'

import { useId, useRef } from 'react'
import type { ReactNode } from 'react'
import { useSignal, useSignalEffect } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import styles from './sheet.module.css'

export interface SheetProps {
  open: boolean
  onClose: () => void
  /** Optional heading. Accepts rich nodes; when present it labels the dialog via `aria-labelledby`. */
  title?: ReactNode
  children: ReactNode
  side?: 'start' | 'end' | 'top' | 'bottom'
}

export function Sheet({ open, onClose, title, children, side = 'end' }: SheetProps) {
  const sheetRef = useRef<HTMLDivElement>(null)
  const titleId = useId()
  const isOpen = useSignal(open)
  isOpen.value = open
  const onCloseRef = useRef(onClose)
  onCloseRef.current = onClose

  useSignalEffect(() => {
    const el = sheetRef.current
    if (!el) return
    if (isOpen.value) {
      try {
        el.showPopover()
      } catch {
        /* noop */
      }
    } else {
      try {
        el.hidePopover()
      } catch {
        /* noop */
      }
    }
  })

  return (
    <div
      ref={sheetRef}
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      // @ts-ignore — popover is a valid HTML attribute not yet in React types
      popover="manual"
      role="dialog"
      aria-modal="true"
      aria-labelledby={title != null ? titleId : undefined}
      data-state={open ? 'open' : 'closed'}
      data-side={side}
      className={styles.sheet}
    >
      <div className={styles.header}>
        {title != null && (
          <span id={titleId} className={styles.title}>
            {title}
          </span>
        )}
        <button
          type="button"
          aria-label={t(builtin.sheet.close)}
          onClick={() => onCloseRef.current()}
          className={styles.close}
        >
          ✕
        </button>
      </div>
      <div className={styles.body}>{children}</div>
    </div>
  )
}

@layer cascivo.component {
  .sheet {
    position: fixed;
    margin: 0;
    padding: 0;
    border: none;
    background: var(--cascivo-color-surface);
    box-shadow: var(--cascivo-shadow-overlay);
    display: flex;
    flex-direction: column;

    /* Transitions for enter/exit */
    transition:
      translate var(--cascivo-motion-enter),
      display var(--cascivo-motion-enter) allow-discrete,
      overlay var(--cascivo-motion-enter) allow-discrete;

    &[data-state='closed'] {
      transition:
        translate var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }

    /* Side: end (right) */
    &[data-side='end'] {
      inset-block: 0;
      inset-inline-end: 0;
      width: min(24rem, 90vw);
      height: 100%;
      border-inline-start: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-overlay) 0 0 var(--cascivo-radius-overlay);
      translate: 100% 0;

      &[data-state='open'] {
        translate: 0 0;
      }

      @starting-style {
        &[data-state='open'] {
          translate: 100% 0;
        }
      }
    }

    /* Side: start (left) */
    &[data-side='start'] {
      inset-block: 0;
      inset-inline-start: 0;
      width: min(24rem, 90vw);
      height: 100%;
      border-inline-end: 1px solid var(--cascivo-color-border);
      border-radius: 0 var(--cascivo-radius-overlay) var(--cascivo-radius-overlay) 0;
      translate: -100% 0;

      &[data-state='open'] {
        translate: 0 0;
      }

      @starting-style {
        &[data-state='open'] {
          translate: -100% 0;
        }
      }
    }

    /* Side: top */
    &[data-side='top'] {
      inset-inline: 0;
      inset-block-start: 0;
      width: 100%;
      height: auto;
      max-height: 80vh;
      border-block-end: 1px solid var(--cascivo-color-border);
      border-radius: 0 0 var(--cascivo-radius-overlay) var(--cascivo-radius-overlay);
      translate: 0 -100%;

      &[data-state='open'] {
        translate: 0 0;
      }

      @starting-style {
        &[data-state='open'] {
          translate: 0 -100%;
        }
      }
    }

    /* Side: bottom */
    &[data-side='bottom'] {
      inset-inline: 0;
      inset-block-end: 0;
      width: 100%;
      height: auto;
      max-height: 80vh;
      border-block-start: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-overlay) var(--cascivo-radius-overlay) 0 0;
      translate: 0 100%;

      &[data-state='open'] {
        translate: 0 0;
      }

      @starting-style {
        &[data-state='open'] {
          translate: 0 100%;
        }
      }
    }

    &::backdrop {
      background-color: rgb(0 0 0 / 0.4);
      opacity: 1;
      transition:
        opacity var(--cascivo-motion-enter),
        display var(--cascivo-motion-enter) allow-discrete,
        overlay var(--cascivo-motion-enter) allow-discrete;

      @starting-style {
        opacity: 0;
      }
    }

    &[data-state='closed']::backdrop {
      opacity: 0;
      transition:
        opacity var(--cascivo-motion-exit),
        display var(--cascivo-motion-exit) allow-discrete,
        overlay var(--cascivo-motion-exit) allow-discrete;
    }
  }

  .header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: var(--cascivo-space-4) var(--cascivo-space-6);
    border-block-end: 1px solid var(--cascivo-color-border);
    flex-shrink: 0;
  }

  .title {
    font-size: var(--cascivo-text-lg);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .close {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    padding: 0;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-muted);
    background: transparent;
    border: none;
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }
  }

  .body {
    padding: var(--cascivo-space-6);
    overflow-y: auto;
    flex: 1;
  }
}
